import numpy as np

class ThompsonSampling:
    """Bayesian bandit for exploration vs exploitation"""
    def __init__(self, n_items):
        self.alpha = np.ones(n_items)  # Beta prior: alpha (successes)
        self.beta = np.ones(n_items)   # Beta prior: beta (failures)

    def recommend(self):
        # Sample from posterior: Beta(alpha, beta)
        samples = np.random.beta(self.alpha, self.beta)
        return np.argmax(samples)

    def update(self, item, reward):
        # reward = 1 (click/engage) or 0 (skip)
        if reward == 1:
            self.alpha[item] += 1
        else:
            self.beta[item] += 1

# UCB: Upper Confidence Bound
# ucb_score = mu_i + sqrt(2 * log(t) / n_i)
# where mu_i = average reward for item i, n_i = times item i was shown
